505     const ConstantRange &CR1, const ConstantRange &CR2,
506     ConstantRange::PreferredRangeType Type) {
507   if (Type == ConstantRange::Unsigned) {
508     if (!CR1.isWrappedSet() && CR2.isWrappedSet())
509       return CR1;
